package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;
import java.io.IOException;

class CSVFormatTest {

    @Test
    void testPrintln() throws IOException {
        // Given
        Appendable out = Mockito.mock(Appendable.class);
        CSVFormat csvFormat = CSVFormat.newFormat(',').withQuote('"').withRecordSeparator("\r\n").withTrailingDelimiter(true);

        // When
        csvFormat.println(out);

        // Then
        Mockito.verify(out).append("\r\n");
    }
}
